(() => {
    let count = 0;
    for (let i = 0; i < trimmed.length; i += 1) {
      if (trimmed[i] !== '$') continue;
      let slashCount = 0;
      for (let j = i - 1; j >= 0 && trimmed[j] === '\\'; j -= 1) {
        slashCount += 1;
      }
      if (slashCount % 2 === 0) {
        count += 1;
      }
    }
    return count;
  })
